const markdown = $input.first().json.markdown;

const systemInstruction = `You are a contract editing assistant. Analyze the provided Markdown document and generate exactly 2 distinct modifications in a JSON array. Return ONLY the raw JSON array containing exactly 2 items conforming to the DocumentChange schema. Do not add markdown blocks, formatting or metadata.

Available Edit Types & Schema:
- {"type":"modify", "target_text":"<copied VERBATIM from source>", "new_text":"<replacement>", "comment":"<optional>", "match_mode":"<optional 'strict' (default) | 'first' | 'all'>", "regex": false}
- {"type":"insert_row", "target_text":"<cell text anchoring row>", "position":"above" or "below", "cells":["col1","col2"]}
- {"type":"delete_row", "target_text":"<cell text anchoring row>"}

Rules:
- target_text must be copied VERBATIM from the document (same punctuation, whitespace, capitalization).
- NEVER include CriticMarkup tags like {++ or {-- in new_text.
- Set match_mode='all' to replace every occurrence in linear order. Omit or use 'strict' to fail on ambiguous matches.`;

const userText = `Here is the document:\n\n${markdown}`;

const geminiPayload = {
  contents: [
    {
      role: "user",
      parts: [
        {
          text: userText
        }
      ]
    }
  ],
  systemInstruction: {
    parts: [
      {
        text: systemInstruction
      }
    ]
  },
  generationConfig: {
    responseMimeType: "application/json",
    temperature: 0
  }
};

return { json: { geminiPayload } };

const response = $input.first().json;
const content = response.candidates[0].content.parts[0].text.trim();
let cleaned = content;
if (cleaned.startsWith('```')) {
  cleaned = cleaned.replace(/^```[a-zA-Z]*\n?/, '');
  cleaned = cleaned.replace(/\n?```$/, '');
}
const changes = JSON.parse(cleaned.trim());

// Forward the binary forward to Apply Turn 1 Edits port
return {
  json: { changes },
  binary: $('Read Baseline Doc').first().binary
};

const markdown = $input.first().json.markdown;

const systemInstruction = `You are a contract reviewer. You will be provided with a raw Markdown document containing CriticMarkup tags representing active tracked changes (such as {++inserted++} or {--deleted--}) along with their IDs (e.g. Chg:1 or Chg:2). Generate a JSON array with exactly two operations: 1) Accept the first change (using its exact Chg:N target_id), and 2) Reply to the comment or change representing the second change (using its exact target_id Com:N or Chg:N, and providing a reply text). Output ONLY the raw JSON array with no formatting or markdown.

Available Review Schema:
- {"type": "accept", "target_id": "Chg:1", "comment": "<optional>"}
- {"type": "reject", "target_id": "Chg:1", "comment": "<optional>"}
- {"type": "reply", "target_id": "Com:2", "text": "<reply text>"}

Rules:
- Use Chg:N and Com:N identifiers exactly as they appear in the Markdown output. Do not invent IDs.`;

const userText = `Here is the document containing tracked changes:\n\n${markdown}`;

const geminiPayload = {
